namespace BlazorApp;

/// <summary>
/// Pages decorated with this attribute are rendered using static server-side rendering
/// instead of the app-wide interactive render mode. This allows access to HttpContext.
/// </summary>
[AttributeUsage(AttributeTargets.Class)]
public class ExcludeFromInteractiveRoutingAttribute : Attribute;

@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application uses cookies to improve your experience.
    We collect only the information necessary to provide our services.
</p>

<h2>Cookie Consent</h2>

@if (HasConsent)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>What We Collect</h2>
<ul>
    <li>Essential cookies required for the application to function</li>
    <li>Preference cookies to remember your settings</li>
</ul>

<h2>Your Rights</h2>
<p>
    You may withdraw consent at any time by clearing your browser cookies.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsent =>
        HttpContext?.Request.Cookies.ContainsKey("consent") == true;
}

